const fs = require('fs');

// Read the template
const template = fs.readFileSync('/job/operating_system/LEASE_RENT_HOUSE_TEMPLATE.html', 'utf-8');

// Define replacement values
const replacements = {
  '{{TENANT_NAME}}': 'Christian Lachausse, Christine Nisbett & Camden Nisbett',
  '{{PROPERTY_ADDRESS}}': '111 E Main Street, Celina, TX 75009',
  '{{MONTHLY_RENT}}': '$1,800.00',
  '{{LEASE_START}}': 'Month-to-Month',
  '{{SECURITY_DEPOSIT}}': '$1,800.00',
  '{{UTILITIES_SECTION}}': 'Tenant will be invoiced for utility bills each month.',
  '{{CUSTOM_TERMS}}': 'Mowing of yard is included in the base rent.',
  '{{DATE}}': new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' }),
  '{{CONTACT_EMAIL}}': 'Sloan@tjmfuneral.com',
  '{{CONTACT_PHONE}}': '(972) 632-2787'
};

// Replace all placeholders
let rendered = template;
for (const [placeholder, value] of Object.entries(replacements)) {
  rendered = rendered.replace(new RegExp(placeholder.replace(/[{}]/g, '\\$&'), 'g'), value);
}

// Write rendered HTML
fs.writeFileSync('/job/tmp/lease.html', rendered);
console.log('Rendered HTML written to /job/tmp/lease.html');

arguments.command:
node -e "
const puppeteer = require('/job/tmp/node_modules/puppeteer');
(async () => {
  const browser = await puppeteer.launch({ 
    headless: 'new', 
    args: ['--no-sandbox', '--disable-setuid-sandbox'] 
  });
  const page = await browser.newPage();
  const html = require('fs').readFileSync('/job/tmp/lease.html', 'utf-8');
  await page.setContent(html, { waitUntil: 'networkidle0' });
  await page.pdf({
    path: '/job/tmp/Lease_Agreement_Christian_Lachausse_111_E_Main_St.pdf',
    format: 'Letter',
    printBackground: true
  });
  await browser.close();
  console.log('PDF generated successfully');
})();
"
